android.extraProguardRules:
# --- Anyvo: Keep-Regeln, damit R8 keine per Reflection genutzten Klassen entfernt ---
# Hermes / React Native Core
-keep,includedescriptorclasses class com.facebook.react.turbomodule.** { *; }
-keep class com.facebook.jni.** { *; }
-keep class com.facebook.hermes.** { *; }
-dontwarn com.facebook.react.**

# Native-Module (per Autolinking / Reflection instanziiert)
-keep class expo.modules.** { *; }
-keep class com.polidea.reactnativeble.** { *; }
-keep class com.bleplx.** { *; }
-dontwarn com.polidea.**
-dontwarn com.bleplx.**

# Sentry
-keep class io.sentry.** { *; }
-dontwarn io.sentry.**

# Google Maps / Play Services
-keep class com.google.android.gms.maps.** { *; }
-dontwarn com.google.android.gms.**

# Enums / Parcelable (Reflection-sicher)
-keepclassmembers enum * { *; }
-keepnames class * implements android.os.Parcelable { *; }
-keepclassmembers class * implements android.os.Parcelable {
    public static final ** CREATOR;
}
